mapper.select:

where 1 = 1

    and (
        s.scheme_code like concat('%', #{keyword}, '%')
        or s.scheme_name like concat('%', #{keyword}, '%')
    )


    and s.scheme_code like concat('%', #{schemeCode}, '%')


    and s.scheme_name like concat('%', #{schemeName}, '%')


    and s.scheme_type = #{schemeType}


    and s.fee_source_mode = #{feeSourceMode}


    and s.currency_code = #{currencyCode}


    and s.scope_type = #{scopeType}


    and s.warehouse_scope_mode = #{warehouseScopeMode}


    and s.status = #{status}


    and date_format(s.effective_time,'%Y%m%d') >= date_format(#{params.effectiveBeginTime},'%Y%m%d')


    and date_format(s.effective_time,'%Y%m%d') <= date_format(#{params.effectiveEndTime},'%Y%m%d')

order by s.effective_priority desc, s.effective_time desc, s.scheme_id desc

select count(1)
from quote_scheme s
where s.status = 'ENABLED'
  and s.scheme_type = #{schemeType}
  and s.effective_priority = #{effectivePriority}
  and (s.expire_time is null or s.expire_time >= #{effectiveTime})

  and s.effective_time <= #{expireTime}


  and s.scheme_id <> #{schemeId}

mapper.insert:
insert into quote_scheme(
    scheme_code, scheme_name, scheme_type, fee_source_mode, currency_code,
    scope_type, warehouse_scope_mode, effective_time, expire_time,
    effective_priority, status, create_by, create_time, remark
) values (
    #{schemeCode}, #{schemeName}, #{schemeType}, #{feeSourceMode}, #{currencyCode},
    #{scopeType}, #{warehouseScopeMode}, #{effectiveTime}, #{expireTime},
    #{effectivePriority}, #{status}, #{createBy}, sysdate(), #{remark}
)

insert into quote_scheme_scope(
    scheme_id, scope_type, scope_key, buyer_level_code, buyer_level_name_snapshot,
    buyer_id, buyer_code_snapshot, buyer_name_snapshot, buyer_short_name_snapshot,
    create_by, create_time, remark
) values (
    #{schemeId}, #{scopeType}, #{scopeKey}, #{buyerLevelCode}, #{buyerLevelNameSnapshot},
    #{buyerId}, #{buyerCodeSnapshot}, #{buyerNameSnapshot}, #{buyerShortNameSnapshot},
    #{createBy}, sysdate(), #{remark}
)

insert into quote_scheme_warehouse(
    scheme_id, warehouse_code, warehouse_name_snapshot, warehouse_kind_snapshot,
    create_by, create_time, remark
) values (
    #{schemeId}, #{warehouseCode}, #{warehouseNameSnapshot}, #{warehouseKindSnapshot},
    #{createBy}, sysdate(), #{remark}
)

